    } else if v > max as f32 {
        max
    } else {
        v as u8
    };
}

fn trace_pixel(frame: &Frame, x: f32, y: f32) -> RGBAF32 {
    let half_width = (frame.width / 2) as f32;
    let half_height = (frame.height / 2) as f32;

    let dx = (x - half_width).abs();
    let dy = (y - half_height).abs();
